def process_entry(raw_json):
    data = json.loads(raw_json)

    m_tx_raw = data["entry"]["m_ptx_wallet_info"]["m_tx"]
    m_tx = json.loads(m_tx_raw)

    print("=== m_tx ===")
    print(json.dumps(m_tx, indent=2))

    vin = m_tx.get("AGGREGATED", {}).get("vin", [])
    total_offsets = 0

    print("\n=== txin_zc_input ===")
    for i, v in enumerate(vin, 1):
        key_offsets = v.get("txin_zc_input", {}).get("key_offsets", [])
        count = len(key_offsets)
        total_offsets += count
        print(f"Vin {i}: {count} key_offsets")

    print(f"\n>>> all key_offsets: {total_offsets}")

process_entry(raw_json)